// Build a Mattermost-ready error message from Error Trigger metadata
// + the original execution data fetched via n8n public API.
//
// Strategy for finding thread context (channel_id, root_id):
//   1. SetVars output (already has reply_root_id pre-computed)
//   2. Read Incident Context output
//   3. Trigger output (When Executed by Another Workflow)
//   4. Fallback channel from Config (no thread)

const errorMeta = $('Error Trigger').first().json || {};
const exec = errorMeta.execution || {};
const wf = errorMeta.workflow || {};
const cfg = $('Config').first().json || {};

const apiResp = $input.first().json || {};
const runData = (apiResp.data && apiResp.data.resultData && apiResp.data.resultData.runData) || {};

// Helper: read first item.json from a node's first run
function nodeOutput(nodeName) {
  const runs = runData[nodeName];
  if (!runs || !runs.length) return null;
  const items = runs[0] && runs[0].data && runs[0].data.main && runs[0].data.main[0];
  return items && items[0] ? items[0].json : null;
}

// Pull context from the most-downstream node available
const setVars = nodeOutput('SetVars');
const incident = nodeOutput('Read Incident Context');
const trigger = nodeOutput('When Executed by Another Workflow');
const ctx = setVars || incident || trigger || {};

// Re-derive reply_root_id when SetVars did not run (early failure)
const replyRootId = ctx.reply_root_id
  || (ctx.is_thread ? ctx.thread_root_id : ctx.post_id)
  || '';
const channelId = ctx.channel_id || cfg.fallback_channel_id;
const hasThread = Boolean(ctx.channel_id && replyRootId);

// Truncate error message to keep Mattermost post readable
function truncate(s, n) {
  if (!s) return '';
  return s.length > n ? s.slice(0, n) + '…' : s;
}

const errMsg = truncate(exec.error && exec.error.message, 1500) || 'Unknown error';
const lastNode = exec.lastNodeExecuted || 'unknown node';
const execUrl = exec.url || '';
const wfName = wf.name || 'unknown workflow';
const execMode = exec.mode || '';

const lines = [
  `:rotating_light: **${wfName}** execution failed`,
  '',
  `**Failed node:** \`${lastNode}\``,
  `**Error:**`,
  '```',
  errMsg,
  '```',
];

if (execUrl) {
  lines.push(`**Execution:** [open in n8n](${execUrl})`);
}
if (execMode) {
  lines.push(`**Mode:** ${execMode}`);
}
if (ctx.user_name) {
  lines.push(`**Original request from:** @${ctx.user_name}${ctx.channel_name ? ' in #' + ctx.channel_name : ''}`);
}
if (!hasThread) {
  lines.push('');
  lines.push('_Note: thread context could not be recovered — posting to fallback channel._');
}

return [{
  json: {
    channel_id: channelId,
    root_id: replyRootId,
    message: lines.join('\n'),
    has_thread_context: hasThread,
    debug: {
      execution_id: exec.id,
      workflow_id: wf.id,
      source: setVars ? 'SetVars' : (incident ? 'Read Incident Context' : (trigger ? 'Trigger' : 'fallback')),
    },
  },
}];
